import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Method;
import java.util.Collections;
import java.util.HashMap;
import java.util.Map;

class CSVRecordTest {

    @Test
    void testValues() throws Exception {
        String[] vals = new String[] {"a", "b", "c"};
        Map<String, Integer> mapping = new HashMap<>();
        mapping.put("col1", 0);
        mapping.put("col2", 1);
        mapping.put("col3", 2);
        String comment = "comment";
        long recordNumber = 123L;

        // Construct CSVRecord instance via constructor
        CSVRecord record = new CSVRecord(vals, mapping, comment, recordNumber);

        // Use reflection to access the package-private values() method
        Method valuesMethod = CSVRecord.class.getDeclaredMethod("values");
        valuesMethod.setAccessible(true);

        String[] result = (String[]) valuesMethod.invoke(record);

        assertArrayEquals(vals, result);
    }
}
